import 'package:bookly/Features/Home/Data/Repos/home_repo.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../../Home/Data/model/book_model.dart';part 'similar_books_state.dart';class SimilarBooksCubit extends Cubit<SimilarBooksState> {  SimilarBooksCubit(this.homeRepo) : super(SimilarBooksInitial());  static BlocProvider get(context) => SimilarBooksCubit.get(context);  final HomeRepo homeRepo;  Future<void> fetchSimilarBooks({required String category}) async {    emit(SimilarBooksLoading());    await homeRepo.fetchSimilarBooks(category: category).then((value) {      value.fold(          (failure) => emit(SimilarBooksFailure(error: failure.errMessage)),          (books) => emit(SimilarBooksSuccess(books: books)));    });  }}